// Strategy interface: all payment strategies must implement this
interface PaymentStrategy {
    void pay(double amount);
}

// Concrete strategy: credit card with fee calculation
class CreditCardStrategy implements PaymentStrategy {
    private double feeRate = 0.03;  // 3% processing fee

    public void pay(double amount) {
        double total = amount * (1 + feeRate);
        System.out.println("Credit: $" + String.format("%.2f", total));
    }
}

// Concrete strategy: cash with no fees
class CashStrategy implements PaymentStrategy {
    public void pay(double amount) {
        System.out.println("Cash: $" + String.format("%.2f", amount));
    }
}

// Context: uses a strategy without knowing its details
class Checkout {
    private PaymentStrategy strategy;
    public Checkout(PaymentStrategy strategy) {
        this.strategy = strategy;
    }
    public void processPayment(double amount) {
        strategy.pay(amount);
    }
}
